#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        // Reconstruct the graph and find the opposite faces
        int* opposite = (int*)malloc(7 * sizeof(int));
        for (int i = 1; i <= 6; i++) {
            opposite[i] = -1;
        }
        for (int i = 0; i < N - 1; i++) {
            if (opposite[A[i]] == -1) {
                opposite[A[i]] = A[i + 1];
            } else if (opposite[A[i]] != A[i + 1]) {
                printf("-1\n");
                free(A);
                free(opposite);
                break;
            }
        }
        if (opposite[A[N - 1]] == -1) {
            printf("-1\n");
        } else {
            for (int i = 1; i <= 6; i++) {
                printf("%d ", opposite[i]);
            }
            printf("\n");
        }
        free(A);
        free(opposite);
    }
    return 0;
}

